// CARD_KEY           = 卡密 (必须，否则程序退出)

// KS_SIGN_API_URL    = 普通版签名API
// KSJSB_SIGN_API_URL = 极速版签名API

// Task               = 任务列表, 逗号分隔
//                      可选: look,box,food,search,dj
//                      默认: look,food,box,search
//
// LOOK_TASK_COUNT    = 看广告次数, 默认30
// BOX_TASK_COUNT     = 宝箱广告次数, 默认30
// FOOD_TASK_COUNT    = 饭补次数, 默认30
// SEARCH_TASK_COUNT  = 搜索次数, 默认30
// DJ_TASK_COUNT      = 短剧广告次数, 默认30


// ROUND_COUNT        = 循环轮数, 默认10 (0=无限循环)
// ROUND_INTERVAL     = 轮间间隔秒数, 默认3600
// MAX_CONCURRENCY    = 最大并发数, 默认666


// WATCH_TIME_MIN     = 最小观看时间(秒), 默认45
// WATCH_TIME_MAX     = 最大观看时间(秒), 默认65
//
// AD_APPEND_ENABLED  = 广告追加开关, 默认开启 (0=关闭)
// FOLLOW_MAX_COUNT   = 追加最大次数, 默认30


// SEARCH_KEYWORDS    = 搜索关键词, 逗号分隔, 默认"短剧小说"
// SEARCH_AD_ENABLED  = 搜索广告开关, 默认开启 (0=关闭)


// KSCOIN_LIMIT       = 金币上限, 默认300000
// LOW_REWARD_THRESHOLD = 低奖励阈值, 默认10
// LOW_REWARD_LIMIT   = 连续低奖励停止次数, 默认5
// ANTISPAM_MAX_COUNT = 风控拦截最大次数, 默认3


// PUSHPLUS_TOKEN     = PushPlus推送Token
// PUSHPLUS_COIN_SUMMARY_EVERY = 推送频率, 默认1 (每隔N轮)

